  const [isLoading, setIsLoading] = useState(false);
  const [step, setStep] = useState("signup");
  const [email, setEmail] = useState("");

  const signupForm = useForm({
    defaultValues: {
      username: "",
      email: "",
      password: "",
    },
  });

  const verifyForm = useForm({
    defaultValues: {
      email: "",
      code: "",
    },
  });

  const onSignup = async (data) => {
    try {
      setIsLoading(true);
      const response = await apiRequest("POST", "/api/auth/signup", data);
      const result = await response.json();

      if (result.ok) {
        setEmail(data.email);
        verifyForm.setValue("email", data.email);
        setStep("verify");
        toast({
          title: "Verification code sent",
          description: "Please check your email for the verification code.",
        });
      } else {
        toast({
          title: "Signup failed",
          description: result.error,
          variant: "destructive",
        });
      }
    } catch (error) {
      toast({
        title: "Signup failed",
        description: error.message,
        variant: "destructive",
      });
    } finally {
      setIsLoading(false);
    }
  };

  const onVerify = async (data) => {
    try {
      setIsLoading(true);
      const signupData = signupForm.getValues();
      const response = await apiRequest("POST", "/api/auth/verify", {
        ...data,
        username: signupData.username,
        password: signupData.password,
      });
      const result = await response.json();

      if (result.ok) {
        localStorage.setItem("token", result.token);
        localStorage.setItem("user", JSON.stringify(result.user));
        toast({
          title: "Account verified",
          description: "Welcome to AI Resume Screening!",
        });
        setLocation("/dashboard");
      } else {
        toast({
          title: "Verification failed",
          description: result.error,
          variant: "destructive",
        });
      }
    } catch (error) {
      toast({
        title: "Verification failed",
        description: error.message,
        variant: "destructive",
      });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
      <Card className="w-full max-w-md">
        <CardHeader className="text-center">
          <CardTitle className="text-2xl font-bold text-slate-800">
            <i className="fas fa-robot text-primary mr-2"></i>
            AI Resume Screening
          </CardTitle>
          <CardDescription>
            {step === "signup" ? "Create your account" : "Verify your email"}
          </CardDescription>
        </CardHeader>
        <CardContent>
          {step === "signup" ? (
            <Form {...signupForm}>
              <form onSubmit={signupForm.handleSubmit(onSignup)} className="space-y-4">
                <FormField
                  control={signupForm.control}
                  name="username"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Username</FormLabel>
                      <FormControl>
                        <Input 
                          placeholder="Enter your username"
                          data-testid="input-username"
                          {...field} 
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
                <FormField
                  control={signupForm.control}
                  name="email"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Email</FormLabel>
                      <FormControl>
                        <Input 
                          placeholder="Enter your email" 
                          type="email"
                          data-testid="input-email"
                          {...field} 
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
                <FormField
                  control={signupForm.control}
                  name="password"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Password</FormLabel>
                      <FormControl>
                        <Input 
                          placeholder="Enter your password" 
                          type="password"
                          data-testid="input-password"
                          {...field} 
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
                <Button 
                  type="submit" 
                  className="w-full" 
                  disabled={isLoading}
                  data-testid="button-signup"
                >
                  {isLoading ? "Creating account..." : "Create Account"}
                </Button>
              </form>
            </Form>
          ) : (
            <Form {...verifyForm}>
              <form onSubmit={verifyForm.handleSubmit(onVerify)} className="space-y-4">
                <div className="text-sm text-slate-600 mb-4">
                  We've sent a 6-digit verification code to <strong>{email}</strong>
                </div>
                <FormField
                  control={verifyForm.control}
                  name="code"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Verification Code</FormLabel>
                      <FormControl>
                        <Input 
                          placeholder="Enter 6-digit code"
                          maxLength={6}
                          data-testid="input-verification-code"
                          {...field} 
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
                <Button 
                  type="submit" 
                  className="w-full" 
                  disabled={isLoading}
                  data-testid="button-verify"
                >
                  {isLoading ? "Verifying..." : "Verify Email"}
                </Button>
              </form>
            </Form>
          )}

          <div className="mt-4 text-center">
            <Button 
              variant="link" 
              onClick={() => setLocation("/login")}
              data-testid="link-login"
            >
              Already have an account? Sign in
            </Button>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

